(function(){
  'use strict';
  const VERSION='OceanJet Command OS V49 Stable Full Source';
  const ROLE_KEY='oj49_role';
  const CLAIMS_KEY='oj49_claims';
  const EVIDENCE_KEY='oj49_evidence';
  const AUDIT_KEY='oj49_audit';
  let oldNavigate=null, oldShowView=null, oldOj42Open=null, oldOj43Open=null, oldBuildDrawer=null;
  let activeStream=null;
  let lastAnalysis=null;

  const $=id=>document.getElementById(id);
  const $$=sel=>Array.from(document.querySelectorAll(sel));
  const esc=v=>String(v==null?'':v).replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));
  const now=()=>new Date().toLocaleString('en-PH',{timeZone:'Asia/Manila',hour12:true});
  const iso=()=>new Date().toISOString();
  const today=()=>new Date().toISOString().slice(0,10);
  const peso=n=>'₱'+Number(n||0).toLocaleString('en-PH',{minimumFractionDigits:2,maximumFractionDigits:2});
  const uid=p=>(p||'OJ')+'-'+Date.now().toString(36).toUpperCase()+'-'+Math.random().toString(36).slice(2,6).toUpperCase();
  function read(k,f){try{const v=localStorage.getItem(k);return v?JSON.parse(v):f}catch(e){return f}}
  function write(k,v){try{localStorage.setItem(k,JSON.stringify(v));return true}catch(e){toast('Storage is full. Export backup or clear old photos.');return false}}
  function audit(action,detail){const a=read(AUDIT_KEY,[]);a.unshift({at:now(),action:String(action||''),detail:String(detail||''),role:getRole()});write(AUDIT_KEY,a.slice(0,500));}
  function toast(msg){try{if(typeof window.toast==='function' && window.toast!==toast){window.toast(msg);return}}catch(e){} let t=$('oj49Toast'); if(!t){t=document.createElement('div');t.id='oj49Toast';t.style.cssText='position:fixed;left:50%;bottom:18px;transform:translateX(-50%);z-index:99999;background:#0f172a;color:#ecfeff;border:1px solid rgba(103,232,249,.35);box-shadow:0 14px 40px rgba(0,0,0,.4);padding:12px 14px;border-radius:16px;font:800 13px system-ui;max-width:92%;text-align:center';document.body.appendChild(t);} t.textContent=msg; clearTimeout(t._h); t._h=setTimeout(()=>t.remove(),2600);}
  function getRole(){const r=(localStorage.getItem(ROLE_KEY)||localStorage.getItem('oj_role')||localStorage.getItem('oj42_role')||'pax').toLowerCase();return /admin/.test(r)?'admin':/cashier|staff|counter/.test(r)?'cashier':'pax'}
  function setRole(r){r=/admin/i.test(r)?'admin':/cashier|staff/i.test(r)?'cashier':'pax';try{localStorage.setItem(ROLE_KEY,r);localStorage.setItem('oj42_role',r);localStorage.setItem('oj_role',r)}catch(e){} audit('role changed',r); closeDrawer49(); renderShell();}
  function roleLabel(){return getRole()==='admin'?'ADMIN CONTROL':getRole()==='cashier'?'COUNTER DESK':'PASSENGER'}
  function can(area){const r=getRole();return area==='admin'?r==='admin':area==='counter'?r==='admin'||r==='cashier':true}
  function ensureView(name){let id='view-'+name;let v=$(id);if(!v){v=document.createElement('div');v.id=id;v.className='view';const app=document.querySelector('.app')||document.body;app.appendChild(v)}return v}
  function showOnly(name){$$('.view').forEach(v=>v.classList.remove('active'));const v=ensureView(name);v.classList.add('active');closeDrawer49();try{window.scrollTo({top:0,behavior:'smooth'})}catch(e){window.scrollTo(0,0)}return v}
  function closeDrawer49(){try{$('sideDrawer')?.classList.remove('open');$('overlay')?.classList.remove('show');$('hamburger')?.classList.remove('open')}catch(e){}}
  function toggleDrawer49(){renderDrawer();const d=$('sideDrawer'),o=$('overlay'),h=$('hamburger');d&&d.classList.toggle('open');o&&o.classList.toggle('show');h&&h.classList.toggle('open')}
  function action(icon,title,sub,target,tone){return `<button type="button" class="oj49-action" onclick="oj49Open('${esc(target)}')"><i>${icon}</i><span><b>${esc(title)}</b><small>${esc(sub)}</small></span></button>`}
  function chip(text,cls){return `<span class="oj49-chip ${cls||''}">${esc(text)}</span>`}
  function allClaims(){let out=[...read(CLAIMS_KEY,[])]; const keys=['oj44_claims','oj43_claims','oj_claims','oceanjet_claims','lost_baggage_claims']; keys.forEach(k=>{const v=read(k,[]); if(Array.isArray(v)) out=out.concat(v)}); const v11=read('oj_damage_master_v11_backup',{cases:[]}); if(Array.isArray(v11.cases)) out=out.concat(v11.cases.map(x=>Object.assign({source:'damage'},x))); const ev=read(EVIDENCE_KEY,[]); out=out.concat(ev.map(x=>Object.assign({source:'evidence'},x))); const seen=new Set(); return out.filter(c=>{const id=idOf(c); if(seen.has(id))return false; seen.add(id); return true;});}
  function idOf(c){return c.claimId||c.caseId||c.id||c.ref||c.evidenceId||uid('OJ-CLAIM')}
  function normClaim(c){return {id:idOf(c),psn:c.psn||c.PSN||c.passengerPsn||'',lastName:c.lastName||c.name||c.passengerName||c.passenger||'',route:c.route||c.destination||c.dest||'',baggage:c.baggage||c.baggageType||c.type||'',damage:c.damageType||c.issue||c.aiSuggestion||c.description||'',severity:c.severity||'',status:c.status||c.claimStatus||c.stage||'Submitted',created:c.createdAt||c.phtTimestamp||c.dateTaken||'',staff:c.staff||c.staffName||'',notes:c.notes||''}}
  function saveClaim(c){const arr=read(CLAIMS_KEY,[]); const id=idOf(c); const idx=arr.findIndex(x=>idOf(x)===id); if(idx>=0)arr[idx]=Object.assign({},arr[idx],c); else arr.unshift(c); write(CLAIMS_KEY,arr.slice(0,500)); audit('claim saved',id);}
  function setClaimStatus(id,status,staffNote){let arr=read(CLAIMS_KEY,[]); let found=false; arr=arr.map(c=>{if(idOf(c)===id){found=true; const tl=Array.isArray(c.timeline)?c.timeline:[]; tl.push({at:now(),status,staff:getRole(),note:staffNote||''}); return Object.assign({},c,{status,staff:roleLabel(),staffNote:staffNote||c.staffNote||'',timeline:tl,updatedAt:iso()})}return c}); if(!found){const c=allClaims().find(x=>idOf(x)===id); if(c){c.status=status;c.staff=roleLabel();c.timeline=[{at:now(),status,staff:getRole(),note:staffNote||''}];arr.unshift(c);found=true;}} write(CLAIMS_KEY,arr); audit('claim status',id+' -> '+status); renderStaffCounter();}
  function timeline(status){const steps=['Submitted','Verified','Processing','Resolved']; const idx=Math.max(0,steps.findIndex(s=>String(status||'').toLowerCase().includes(s.toLowerCase()))); return `<div class="oj49-timeline">${steps.map((s,i)=>`<div class="oj49-step ${i<=idx?'on':''}">${s}</div>`).join('')}</div>`}

  function renderShell(){document.body.classList.add('oj49-ready'); try{document.title='OceanJet Command OS V49'}catch(e){} const rb=$('roleBadge'); if(rb)rb.textContent=roleLabel(); const b=$('headerLogoutBtn'); if(b){b.style.display='inline-flex';b.onclick=()=> getRole()==='pax'?renderLogin():setRole('pax'); b.title=getRole()==='pax'?'Open staff login':'Logout to Passenger';} renderDrawer(); renderHome(); closeDrawer49();}
  function renderDrawer(){const box=$('drawerMenu'); if(!box)return; const r=getRole(); const item=(ico,t,sub,v)=>`<div class="drawer-item oj49-menuItem" onclick="oj49Open('${esc(v)}')"><i>${ico}</i><span><b>${esc(t)}</b><small>${esc(sub)}</small></span></div>`; let html=`<div class="oj49-drawer-head"><b>OceanJet Command OS</b><small>${esc(roleLabel())} · stable full source</small></div><div class="oj49-group">Passenger</div>`+item('🏠','Home','Guided public dashboard','home')+item('🧾','Start Damage Claim','PSN, baggage, evidence','start-claim')+item('🧮','Baggage Calculator','Official baggage fee logic','calculator')+item('🔎','Track Claim','Search status by PSN/name/ID','track')+item('📹','Damage Scanner','Manual-start smart camera','scanner'); if(can('counter')) html+=`<div class="oj49-group">Counter Desk</div>`+item('👥','Staff Counter','Queue, verify, process','staff')+item('⏳','Pending Claims','Submitted claim list','pending')+item('✅','Verify Claim','PSN/name/claim lookup','verify')+item('📄','Receipts','Cashier and evidence PDFs','reports')+item('📊','Daily Summary','Counter totals','daily'); if(can('admin')) html+=`<div class="oj49-group">Admin Control</div>`+item('🗼','Dashboard','Control tower metrics','admin')+item('📚','Master Log','All local claims/evidence','master')+item('📑','PDF Reports','Receipt, log, audit exports','reports')+item('🧿','Transaction Audit','Actions and changes','audit')+item('💾','Backup / Restore','JSON backup tools','backup')+item('⚙️','Settings','Role and system info','settings'); html+=`<div class="oj49-group">Access</div>`+(r==='pax'?item('🔐','Staff Login','Cashier/Admin area','login'):item('🚪','Passenger Mode','Hide staff tools','logout')); box.innerHTML=html;}
  function renderHome(){const r=getRole(); const v=showOnly('dashboard'); const claims=allClaims().map(normClaim); const pending=claims.filter(c=>/submit|pending|new/i.test(c.status)).length; const resolved=claims.filter(c=>/resolved|closed|done/i.test(c.status)).length; let cards=action('🧾','Start Damage Claim','Guided PSN + baggage + evidence flow.','start-claim')+action('🧮','Baggage Calculator','Open preserved fare and baggage price logic.','calculator')+action('🔎','Track Claim','Check status using PSN, last name, or ID.','track')+action('📹','Damage Scanner','Manual-start scanner with image autofill.','scanner'); if(can('counter')) cards+=action('👥','Staff Counter','Queue, verify, status updates, receipts.','staff')+action('📊','Daily Summary','Counter totals and cashier report.','daily'); if(can('admin')) cards+=action('🗼','Admin Control Tower','Master log, exports, audit, backups.','admin')+action('💾','Backup / Restore','Download or restore local database.','backup'); v.innerHTML=`<div class="oj49-shell"><div class="oj49-hero"><div class="oj49-title"><div><h1>${r==='admin'?'Admin Control Tower':r==='cashier'?'Counter Desk Home':'Passenger Baggage Portal'}</h1><div class="oj49-sub">Stable full-source build. Passenger opens by default; staff/admin modules stay hidden until login. Scanner and PDFs are manual, safe, and non-blank.</div></div>${chip(roleLabel(),r==='admin'?'red':r==='cashier'?'gold':'ok')}</div><div class="oj49-grid3"><div class="oj49-card oj49-kpi"><b>${claims.length}</b><span>Total local records</span></div><div class="oj49-card oj49-kpi"><b>${pending}</b><span>Pending/new</span></div><div class="oj49-card oj49-kpi"><b>${resolved}</b><span>Resolved/closed</span></div></div></div><div class="oj49-grid">${cards}</div><div class="oj49-card" style="margin-top:14px"><h3>Universal Search</h3><input id="oj49HomeSearch" class="oj49-input" placeholder="Search PSN, last name, claim ID, route, damage type, date, staff" oninput="oj49SearchHome()"><div id="oj49HomeResults" style="margin-top:10px"><div class="oj49-note">Type to search claims, evidence, and counter records stored on this device.</div></div></div></div>`;}
  window.oj49SearchHome=function(){const q=($('oj49HomeSearch')?.value||'').toLowerCase().trim(); const box=$('oj49HomeResults'); if(!box)return; if(!q){box.innerHTML='<div class="oj49-note">Type to search claims, evidence, and counter records stored on this device.</div>';return} const rows=allClaims().map(normClaim).filter(c=>JSON.stringify(c).toLowerCase().includes(q)).slice(0,12); box.innerHTML=rows.length?rows.map(c=>claimRow(c,false)).join(''):'<div class="oj49-note">No matching local record.</div>';};
  function claimRow(c,withActions){return `<div class="oj49-row"><div><b>${esc(c.id)}</b><small>${esc(c.lastName||'Passenger')} · PSN ${esc(c.psn||'not saved')} · ${esc(c.route||'route not saved')}</small><small>${esc(c.damage||c.baggage||'Claim')} · ${esc(c.status)}</small>${timeline(c.status)}</div>${withActions?`<div class="oj49-tools"><button onclick="oj49SetStatus('${esc(c.id)}','Verified')">Verify</button><button class="gold" onclick="oj49SetStatus('${esc(c.id)}','Processing')">Process</button><button class="primary" onclick="oj49SetStatus('${esc(c.id)}','Resolved')">Resolve</button><button class="danger" onclick="oj49SetStatus('${esc(c.id)}','Rejected')">Reject</button><button onclick="oj49PDFClaim('${esc(c.id)}')">PDF</button></div>`:''}</div>`}
  window.oj49SetStatus=(id,status)=>setClaimStatus(id,status,($('oj49StaffNote')?.value||''));

  function renderLogin(){const v=showOnly('oj49-login'); v.innerHTML=`<div class="oj49-shell"><div class="oj49-hero"><div class="oj49-title"><div><h2>Staff Access</h2><div class="oj49-sub">Passenger mode is public. Cashier and Admin tools require login and are separated by role.</div></div>${chip('ROLE GATE','gold')}</div></div><div class="oj49-grid"><div class="oj49-card"><h3>Cashier Login</h3><label class="oj49-label">Passcode</label><input id="oj49CashierPass" class="oj49-input" type="password" placeholder="Enter cashier passcode"><div class="oj49-tools"><button class="primary" onclick="oj49DoLogin('cashier')">Login as Cashier</button></div><div class="oj49-note">Cashier sees Passenger + Counter Desk only.</div></div><div class="oj49-card"><h3>Admin Login</h3><label class="oj49-label">Passcode</label><input id="oj49AdminPass" class="oj49-input" type="password" placeholder="Enter admin passcode"><div class="oj49-tools"><button class="danger" onclick="oj49DoLogin('admin')">Login as Admin</button></div><div class="oj49-note">Admin can access all tools, exports, logs, backup, restore, and settings.</div></div></div></div>`;}
  window.oj49DoLogin=function(type){const val=(type==='admin'?$('oj49AdminPass')?.value:$('oj49CashierPass')?.value)||''; if(type==='admin' && /^(admin|oceanjet|ojadmin|1234|admin123)$/i.test(val)){setRole('admin');return} if(type==='cashier' && /^(cashier|staff|counter|ojcashier|1234|cashier123)$/i.test(val)){setRole('cashier');return} toast('Incorrect passcode. Use authorized staff credentials.'); audit('failed login',type);};

  function renderStartClaim(){const v=showOnly('oj49-start-claim'); v.innerHTML=`<div class="oj49-shell"><div class="oj49-hero"><div class="oj49-title"><div><h2>Start Damage Claim</h2><div class="oj49-sub">Guided passenger flow: PSN, last name, route/trip, baggage details, evidence, review, receipt.</div></div>${chip('PASSENGER FLOW','ok')}</div></div><div class="oj49-card" style="margin-top:14px"><div class="oj49-grid"><div><label class="oj49-label">PSN</label><input id="oj49Psn" class="oj49-input" placeholder="Passenger Serial Number / PSN"></div><div><label class="oj49-label">Last Name</label><input id="oj49Last" class="oj49-input" placeholder="Passenger last name"></div><div><label class="oj49-label">Route / Trip</label><input id="oj49Route" class="oj49-input" placeholder="Example: Cebu to Ormoc"></div><div><label class="oj49-label">Baggage Tag / Stub</label><input id="oj49Tag" class="oj49-input" placeholder="Tag or claim stub number"></div><div><label class="oj49-label">Baggage Details</label><input id="oj49Bag" class="oj49-input" placeholder="Color, size, type, weight"></div><div><label class="oj49-label">Damage Severity</label><select id="oj49Severity" class="oj49-select"><option value="">Select severity</option><option>Minor</option><option>Moderate</option><option>Severe</option></select></div></div><label class="oj49-label">Damage Details</label><textarea id="oj49Damage" class="oj49-textarea" rows="4" placeholder="Describe dent, crack, scratch, missing wheel, broken zipper, wet baggage, etc."></textarea><label class="oj49-label">Photo Evidence</label><input id="oj49ClaimPhoto" class="oj49-input" type="file" accept="image/*" onchange="oj49ClaimPhotoPreview(this.files)"><div id="oj49ClaimPhotoBox"></div><div class="oj49-tools"><button class="primary" onclick="oj49SubmitClaim()">Submit Claim + Generate Reference</button><button onclick="oj49Open('scanner')">Use Smart Damage Scanner</button><button onclick="oj49PDFClaim()">Claim PDF Receipt</button></div></div><div id="oj49ClaimResult"></div></div>`;}
  window.oj49ClaimPhotoPreview=async function(files){const f=files&&files[0]; if(!f)return; const url=await fileToDataURL(f); $('oj49ClaimPhotoBox').innerHTML=`<div class="oj49-row"><img class="oj49-imgthumb" src="${url}"><div><b>Photo attached</b><small>${esc(f.name)} · stored locally after submit</small></div></div>`; $('oj49ClaimPhotoBox').dataset.photo=url;};
  window.oj49SubmitClaim=function(){const c={claimId:uid('OJ-CLM'),psn:val('oj49Psn'),lastName:val('oj49Last'),route:val('oj49Route'),tagNo:val('oj49Tag'),baggage:val('oj49Bag'),damageType:val('oj49Damage'),severity:val('oj49Severity'),status:'Submitted',createdAt:now(),staff:'',photo:$('oj49ClaimPhotoBox')?.dataset.photo||'',timeline:[{at:now(),status:'Submitted',staff:'Passenger',note:'Claim submitted'}]}; if(!c.psn||!c.lastName){toast('PSN and last name are required.');return} saveClaim(c); $('oj49ClaimResult').innerHTML=`<div class="oj49-card" style="margin-top:14px"><h3>Claim Submitted</h3>${claimRow(normClaim(c),false)}<div class="oj49-tools"><button class="primary" onclick="oj49PDFClaim('${esc(c.claimId)}')">Download Claim PDF Receipt</button><button onclick="oj49Open('track')">Track Claim</button></div></div>`; toast('Claim reference generated: '+c.claimId);};
  function val(id){return ($(id)?.value||'').trim()}

  function renderTrack(){const v=showOnly('oj49-track'); v.innerHTML=`<div class="oj49-shell"><div class="oj49-hero"><div class="oj49-title"><div><h2>Track Claim</h2><div class="oj49-sub">Passenger status view. Search by PSN, last name, claim ID, route, damage type, or date.</div></div>${chip('STATUS','ok')}</div></div><div class="oj49-card" style="margin-top:14px"><input id="oj49TrackQ" class="oj49-input" placeholder="Enter PSN, last name, claim ID, route, damage type" oninput="oj49TrackSearch()"><div id="oj49TrackResults" style="margin-top:10px"></div></div></div>`; oj49TrackSearch();}
  window.oj49TrackSearch=function(){const q=($('oj49TrackQ')?.value||'').toLowerCase().trim(); let arr=allClaims().map(normClaim); if(q)arr=arr.filter(c=>JSON.stringify(c).toLowerCase().includes(q)); arr=arr.slice(0,20); const box=$('oj49TrackResults'); if(box)box.innerHTML=arr.length?arr.map(c=>claimRow(c,false)).join(''):'<div class="oj49-note">No claim found yet. Submit a claim first or check spelling.</div>';};

  function renderStaffCounter(){if(!can('counter')){renderLogin();return} const claims=allClaims().map(normClaim); const pending=claims.filter(c=>!/resolved|rejected|closed/i.test(c.status)); const v=showOnly('oj49-staff'); v.innerHTML=`<div class="oj49-shell"><div class="oj49-hero"><div class="oj49-title"><div><h2>Staff Counter</h2><div class="oj49-sub">Functional counter queue with claim verification, status buttons, staff notes, receipts, and daily summary.</div></div>${chip('COUNTER READY','gold')}</div><div class="oj49-grid3"><div class="oj49-card oj49-kpi"><b>${claims.length}</b><span>Total claims</span></div><div class="oj49-card oj49-kpi"><b>${pending.length}</b><span>Open queue</span></div><div class="oj49-card oj49-kpi"><b>${claims.filter(c=>/resolved|closed/i.test(c.status)).length}</b><span>Resolved</span></div></div></div><div class="oj49-card" style="margin-top:14px"><h3>Quick Search / Verify Passenger</h3><input id="oj49StaffSearch" class="oj49-input" placeholder="Search PSN, last name, claim ID, route, damage, staff" oninput="oj49FilterStaff()"><label class="oj49-label">Staff Notes</label><textarea id="oj49StaffNote" class="oj49-textarea" rows="2" placeholder="Verification or processing notes"></textarea><div class="oj49-tools"><button onclick="oj49PDFDaily()">Daily Summary PDF</button><button onclick="oj49Open('reports')">PDF Center</button><button onclick="oj49Open('start-claim')">Create Claim</button></div></div><div class="oj49-card" style="margin-top:14px"><h3>Submitted Claim Queue</h3><div id="oj49StaffRows">${(pending.length?pending:claims).slice(0,40).map(c=>claimRow(c,true)).join('')||'<div class="oj49-note">No claim records yet. Passenger claims and scanner evidence will appear here.</div>'}</div></div></div>`;}
  window.oj49FilterStaff=function(){const q=($('oj49StaffSearch')?.value||'').toLowerCase().trim();let rows=allClaims().map(normClaim); if(q)rows=rows.filter(c=>JSON.stringify(c).toLowerCase().includes(q)); const box=$('oj49StaffRows'); if(box)box.innerHTML=rows.length?rows.slice(0,50).map(c=>claimRow(c,true)).join(''):'<div class="oj49-note">No matching claim.</div>';};

  function renderAdmin(){if(!can('admin')){renderLogin();return} const claims=allClaims().map(normClaim); const sev=claims.filter(c=>/severe/i.test(c.severity)).length; const verified=claims.filter(c=>/verified/i.test(c.status)).length; const rejected=claims.filter(c=>/rejected/i.test(c.status)).length; const v=showOnly('oj49-admin'); v.innerHTML=`<div class="oj49-shell"><div class="oj49-hero"><div class="oj49-title"><div><h2>Admin Control Tower</h2><div class="oj49-sub">Full monitoring, master logs, transaction audit, PDF reports, backup/restore, and grouped advanced modules.</div></div>${chip('FULL ACCESS','red')}</div><div class="oj49-grid3"><div class="oj49-card oj49-kpi"><b>${claims.length}</b><span>Total claims</span></div><div class="oj49-card oj49-kpi"><b>${claims.filter(c=>/submit|pending|new/i.test(c.status)).length}</b><span>Pending</span></div><div class="oj49-card oj49-kpi"><b>${verified}</b><span>Verified</span></div><div class="oj49-card oj49-kpi"><b>${claims.filter(c=>/resolved|closed/i.test(c.status)).length}</b><span>Resolved</span></div><div class="oj49-card oj49-kpi"><b>${rejected}</b><span>Rejected</span></div><div class="oj49-card oj49-kpi"><b>${sev}</b><span>Severe damage</span></div></div></div><div class="oj49-grid">${action('📚','Master Claim Log','View all local claim and evidence records.','master')}${action('📑','PDF Export Center','Master log, audit, status, evidence reports.','reports')}${action('🧿','Transaction Audit','Review role and claim activity logs.','audit')}${action('💾','Backup / Restore','Export/import local database JSON.','backup')}</div></div>`;}
  function renderMaster(){if(!can('admin')){renderLogin();return} const claims=allClaims().map(normClaim); const v=showOnly('oj49-master'); v.innerHTML=`<div class="oj49-shell"><div class="oj49-hero"><div class="oj49-title"><div><h2>Master Claim Log</h2><div class="oj49-sub">Admin-only consolidated claims, scanner evidence, route, damage, status, staff, and timeline.</div></div>${chip(String(claims.length)+' RECORDS','red')}</div></div><div class="oj49-card" style="margin-top:14px"><input id="oj49MasterQ" class="oj49-input" placeholder="Universal search" oninput="oj49MasterSearch()"><div id="oj49MasterRows" style="margin-top:10px">${claims.slice(0,80).map(c=>claimRow(c,true)).join('')||'<div class="oj49-note">No local records yet.</div>'}</div></div></div>`;}
  window.oj49MasterSearch=function(){const q=($('oj49MasterQ')?.value||'').toLowerCase().trim(); let rows=allClaims().map(normClaim); if(q)rows=rows.filter(c=>JSON.stringify(c).toLowerCase().includes(q)); $('oj49MasterRows').innerHTML=rows.length?rows.slice(0,100).map(c=>claimRow(c,true)).join(''):'<div class="oj49-note">No matching record.</div>';};
  function renderAudit(){if(!can('admin')){renderLogin();return} const arr=read(AUDIT_KEY,[]); const v=showOnly('oj49-audit'); v.innerHTML=`<div class="oj49-shell"><div class="oj49-hero"><div class="oj49-title"><div><h2>Transaction Audit</h2><div class="oj49-sub">Role changes, claim updates, scanner saves, PDF exports, backup and restore events.</div></div>${chip(String(arr.length)+' LOGS','red')}</div></div><div class="oj49-card" style="margin-top:14px">${arr.slice(0,120).map(a=>`<div class="oj49-row"><div><b>${esc(a.action)}</b><small>${esc(a.at)} · ${esc(a.role)}</small><small>${esc(a.detail)}</small></div></div>`).join('')||'<div class="oj49-note">No audit logs yet.</div>'}<div class="oj49-tools"><button onclick="oj49PDFAudit()">Export Audit PDF</button></div></div></div>`;}

  async function fileToDataURL(file){return new Promise((res,rej)=>{const r=new FileReader();r.onload=()=>res(r.result);r.onerror=rej;r.readAsDataURL(file)})}
  async function loadImage(src){return new Promise((res,rej)=>{const im=new Image();im.onload=()=>res(im);im.onerror=rej;im.src=src})}
  async function analyzeImage(dataUrl,source){const img=await loadImage(dataUrl); const c=document.createElement('canvas'); const max=360; const ratio=Math.min(max/img.width,max/img.height,1); c.width=Math.max(1,Math.round(img.width*ratio)); c.height=Math.max(1,Math.round(img.height*ratio)); const ctx=c.getContext('2d',{willReadFrequently:true}); ctx.drawImage(img,0,0,c.width,c.height); const data=ctx.getImageData(0,0,c.width,c.height).data; let r=0,g=0,b=0,n=0,dark=0,bright=0,sat=0; const bins={Black:0,Gray:0,White:0,Blue:0,Red:0,Brown:0,Green:0,Yellow:0,Purple:0}; for(let i=0;i<data.length;i+=16){const R=data[i],G=data[i+1],B=data[i+2]; const mx=Math.max(R,G,B),mn=Math.min(R,G,B); r+=R;g+=G;b+=B;n++; if(mx<55)dark++; if(mn>205)bright++; if(mx-mn>45)sat++; const name=colorName(R,G,B); bins[name]=(bins[name]||0)+1;} r/=n;g/=n;b/=n; let dom=Object.entries(bins).sort((a,b)=>b[1]-a[1])[0]?.[0]||colorName(r,g,b); let edge=0,checks=0; const step=4; for(let y=0;y<c.height-step;y+=step){for(let x=0;x<c.width-step;x+=step){const i=(y*c.width+x)*4,j=(y*c.width+x+step)*4,k=((y+step)*c.width+x)*4; edge+=Math.abs(data[i]-data[j])+Math.abs(data[i+1]-data[j+1])+Math.abs(data[i+2]-data[j+2])+Math.abs(data[i]-data[k])+Math.abs(data[i+1]-data[k+1])+Math.abs(data[i+2]-data[k+2]);checks++;}} edge=checks?edge/checks:0; const aspect=img.width/img.height; const size=img.width*img.height>1600000?'Large':img.width*img.height>650000?'Medium':'Small'; const baggageType=aspect>1.45?'Duffel / elongated baggage':edge>95?'Soft fabric / textured luggage':dark/n>.55?'Dark hard-shell suitcase':'Hard-shell or box luggage'; const damageScore=Math.min(100,Math.round(edge*.45+(dark/n)*18+(sat/n)*18)); const damageType=damageScore>62?'Possible dent/scratch concentration':damageScore>42?'Surface marks / scuff suspected':'No clear heavy damage detected'; const severity=damageScore>68?'Severe':damageScore>46?'Moderate':'Minor'; const quality=Math.max(18,Math.min(98,Math.round(35+(bright/n<.72?18:4)+(edge>35?18:7)+(img.width>700?13:5)+(sat/n>0.05?8:3)+(dark/n<0.85?6:0)))); const barcode=detectStripes(ctx,c.width,c.height)?'Possible tag/barcode pattern':'Not detected'; return {id:uid('OJ-DMG'),createdAt:now(),source:source||'image',photo:dataUrl,color:dom,size,baggageType,damageType,severity,quality,barcode,destination:'',claimRef:'',notes:'Auto-filled locally from actual image pixels. Destination/tag require visible readable tag or manual confirmation.',autoSummary:`Image ${img.width}×${img.height}; dominant color ${dom}; texture score ${edge.toFixed(0)}; damage score ${damageScore}/100.`};}
  function colorName(R,G,B){const mx=Math.max(R,G,B),mn=Math.min(R,G,B); if(mx<65)return 'Black'; if(mn>205)return 'White'; if(mx-mn<28)return 'Gray'; if(R>G*1.25&&R>B*1.25)return G>95?'Brown':'Red'; if(B>R*1.2&&B>G*1.05)return 'Blue'; if(G>R*1.12&&G>B*1.08)return 'Green'; if(R>170&&G>140&&B<105)return 'Yellow'; if(R>110&&B>110&&G<115)return 'Purple'; return 'Mixed/Patterned'}
  function detectStripes(ctx,w,h){try{const y=Math.floor(h*.5),img=ctx.getImageData(Math.floor(w*.18),y,Math.floor(w*.64),1).data;let changes=0,prev=null;for(let i=0;i<img.length;i+=4){const lum=(img[i]+img[i+1]+img[i+2])/3>128?1:0;if(prev!==null&&lum!==prev)changes++;prev=lum}return changes>18}catch(e){return false}}
  function renderScanner(){const v=showOnly('oj49-scanner'); v.innerHTML=`<div class="oj49-shell"><div class="oj49-hero"><div class="oj49-title"><div><h2>Smart AR Damage Scanner</h2><div class="oj49-sub">Manual start only. It does not use PALOMPON / Unknown defaults. Fields are filled after real camera capture or image upload analysis.</div></div>${chip('NO AUTO-RUN','ok')}</div></div><div class="oj49-grid" style="align-items:start"><div class="oj49-card"><div class="oj49-scanner-stage"><video id="oj49Video" playsinline muted style="display:none"></video><canvas id="oj49Canvas" style="display:none"></canvas><img id="oj49Preview" alt="Evidence preview" style="display:none"><div id="oj49ScannerEmpty" class="oj49-note">Camera is stopped. Press Start Camera or upload an image. No fields will be filled until an actual image is analyzed.</div><div class="oj49-reticle"></div><div class="oj49-scanline" style="display:none" id="oj49ScanLine"></div></div><div class="oj49-tools"><button class="primary" onclick="oj49StartCamera()">Start Camera</button><button onclick="oj49CaptureFrame()">Capture / Analyze</button><button class="danger" onclick="oj49StopCamera()">Stop Camera</button><button onclick="oj49Retake()">Retake</button></div><label class="oj49-label">Upload Image Fallback</label><input class="oj49-input" type="file" accept="image/*" onchange="oj49UploadAnalyze(this.files)"><div id="oj49CameraHelp" class="oj49-note" style="margin-top:10px">If camera permission is blocked, use upload fallback. Weak internet will not break this scanner because the analysis runs locally.</div></div><div class="oj49-card"><h3>Auto-detected Fields</h3><div id="oj49AnalysisBox" class="oj49-analysis waiting"><b>Waiting for image</b><small style="display:block;color:var(--oj49-muted);margin-top:4px">Color, size, baggage type, damage, severity, and evidence score will appear after capture/upload.</small><div class="oj49-meter"><span style="width:0%"></span></div></div><label class="oj49-label">Detected / Manual Destination</label><select id="oj49ScanDest" class="oj49-select"><option value="">Not detected from image - select if visible</option><option>CEBU</option><option>ORMOC</option><option>PALOMPON</option><option>TAGBILARAN</option><option>MAASIN</option><option>SURIGAO</option><option>SIQUIJOR</option><option>DUMAGUETE</option><option>GETAFE</option></select><label class="oj49-label">Claim Stub / Tag Number</label><input id="oj49ScanTag" class="oj49-input" placeholder="Auto if barcode readable, otherwise manual"><label class="oj49-label">Severity Confirmation</label><select id="oj49ScanSeverity" class="oj49-select"><option value="">Analyze image first</option><option>Minor</option><option>Moderate</option><option>Severe</option></select><label class="oj49-label">Staff / Shift</label><input id="oj49ScanStaff" class="oj49-input" placeholder="Dock Staff"><label class="oj49-label">Notes</label><textarea id="oj49ScanNotes" class="oj49-textarea" rows="3" placeholder="Manual damage tag or staff note"></textarea><div class="oj49-tools"><button class="primary" onclick="oj49SaveEvidence()">Save Evidence</button><button onclick="oj49PDFEvidence()">Evidence PDF</button></div></div></div><div class="oj49-card" style="margin-top:14px"><h3>Recent Evidence</h3><div id="oj49RecentEvidence"></div></div></div>`; renderRecentEvidence();}
  window.oj49StartCamera=async function(){try{oj49StopCamera(false); const video=$('oj49Video'); const stream=await navigator.mediaDevices.getUserMedia({video:{facingMode:{ideal:'environment'}},audio:false}); activeStream=stream; video.srcObject=stream; video.style.display='block'; $('oj49Preview').style.display='none'; $('oj49Canvas').style.display='none'; $('oj49ScannerEmpty').style.display='none'; $('oj49ScanLine').style.display='block'; await video.play(); toast('Camera started. Tap Capture / Analyze when the baggage is clear.'); audit('camera started','manual')}catch(e){$('oj49CameraHelp').innerHTML='Camera could not start: '+esc(e.message||e.name||'permission blocked')+'<br>Use Upload Image Fallback or allow camera permission in browser settings.'; toast('Camera blocked. Use upload fallback.'); audit('camera error',e.message||e.name||'')}};
  window.oj49StopCamera=function(showMsg=true){try{if(activeStream){activeStream.getTracks().forEach(t=>t.stop());activeStream=null} const v=$('oj49Video'); if(v){v.pause();v.srcObject=null;v.style.display='none'} const line=$('oj49ScanLine'); if(line)line.style.display='none'; if(showMsg)toast('Camera stopped.')}catch(e){}};
  window.oj49CaptureFrame=async function(){try{const video=$('oj49Video'); if(!video||!video.videoWidth){toast('Start camera first or upload an image.');return} const c=$('oj49Canvas'); c.width=video.videoWidth;c.height=video.videoHeight; c.getContext('2d').drawImage(video,0,0,c.width,c.height); const data=c.toDataURL('image/jpeg',.82); await setPreviewAndAnalyze(data,'camera capture');}catch(e){toast('Capture failed safely. Try upload fallback.'); audit('capture error',e.message||e.name||'')}};
  window.oj49UploadAnalyze=async function(files){try{const f=files&&files[0]; if(!f){return} const data=await fileToDataURL(f); await setPreviewAndAnalyze(data,'upload: '+f.name);}catch(e){toast('Image upload analysis failed. Try another photo.'); audit('upload analyze error',e.message||e.name||'')}};
  async function setPreviewAndAnalyze(data,source){const img=$('oj49Preview'); img.src=data; img.style.display='block'; $('oj49Video').style.display='none'; $('oj49ScannerEmpty').style.display='none'; lastAnalysis=await analyzeImage(data,source); updateAnalysisUI(); audit('image analyzed',lastAnalysis.id+' '+lastAnalysis.color+' '+lastAnalysis.damageType);}
  window.oj49Retake=function(){lastAnalysis=null; const img=$('oj49Preview'); if(img){img.removeAttribute('src');img.style.display='none'} const empty=$('oj49ScannerEmpty'); if(empty)empty.style.display='block'; updateAnalysisUI(); toast('Scanner reset. Capture or upload a new image.');};
  function updateAnalysisUI(){const box=$('oj49AnalysisBox'); if(!box)return; if(!lastAnalysis){box.className='oj49-analysis waiting';box.innerHTML='<b>Waiting for image</b><small style="display:block;color:var(--oj49-muted);margin-top:4px">No destination/default values are used. Capture/upload first.</small><div class="oj49-meter"><span style="width:0%"></span></div>'; return} box.className='oj49-analysis'; box.innerHTML=`<b>${esc(lastAnalysis.id)}</b><small style="display:block;color:var(--oj49-muted);margin-top:5px">Color: <b>${esc(lastAnalysis.color)}</b> · Size: <b>${esc(lastAnalysis.size)}</b> · Type: <b>${esc(lastAnalysis.baggageType)}</b></small><small style="display:block;color:var(--oj49-muted);margin-top:5px">Damage: <b>${esc(lastAnalysis.damageType)}</b> · Severity: <b>${esc(lastAnalysis.severity)}</b> · Barcode: ${esc(lastAnalysis.barcode)}</small><small style="display:block;color:var(--oj49-muted);margin-top:5px">${esc(lastAnalysis.autoSummary)}</small><div class="oj49-meter"><span style="width:${Number(lastAnalysis.quality)||0}%"></span></div><span class="oj49-status" style="margin-top:8px">Evidence quality ${Number(lastAnalysis.quality)||0}%</span>`; if($('oj49ScanSeverity')&&!$('oj49ScanSeverity').value)$('oj49ScanSeverity').value=lastAnalysis.severity; if($('oj49ScanTag')&&lastAnalysis.barcode!=='Not detected'&&!$('oj49ScanTag').value)$('oj49ScanTag').placeholder='Possible tag detected - type visible number';}
  window.oj49SaveEvidence=function(){if(!lastAnalysis){toast('Capture or upload an image first.');return} const rec=Object.assign({},lastAnalysis,{destination:val('oj49ScanDest'),claimRef:val('oj49ScanTag'),severity:val('oj49ScanSeverity')||lastAnalysis.severity,staff:val('oj49ScanStaff')||roleLabel(),notes:(val('oj49ScanNotes')||lastAnalysis.notes)}); const arr=read(EVIDENCE_KEY,[]); arr.unshift(rec); write(EVIDENCE_KEY,arr.slice(0,180)); saveClaim({claimId:rec.id,psn:'',lastName:'',route:rec.destination,tagNo:rec.claimRef,baggage:rec.color+' '+rec.size+' '+rec.baggageType,damageType:rec.damageType,severity:rec.severity,status:'Submitted',createdAt:rec.createdAt,staff:rec.staff,notes:rec.notes,photo:rec.photo,timeline:[{at:now(),status:'Submitted',staff:rec.staff,note:'Evidence saved from Smart AR scanner'}]}); audit('evidence saved',rec.id); toast('Evidence saved and added to Staff Counter: '+rec.id); renderRecentEvidence();};
  function renderRecentEvidence(){const box=$('oj49RecentEvidence'); if(!box)return; const arr=read(EVIDENCE_KEY,[]).slice(0,8); box.innerHTML=arr.length?arr.map(e=>`<div class="oj49-row"><div style="display:flex;gap:10px;align-items:center"><img class="oj49-imgthumb" src="${esc(e.photo)}"><div><b>${esc(e.id)}</b><small>${esc(e.color)} · ${esc(e.size)} · ${esc(e.damageType)} · ${esc(e.severity)} · ${esc(e.quality)}%</small><small>${esc(e.createdAt)}</small></div></div><div class="oj49-tools"><button onclick="oj49PDFEvidence('${esc(e.id)}')">PDF</button></div></div>`).join(''):'<div class="oj49-note">No evidence saved yet.</div>';}

  function pdfEscape(s){return String(s==null?'':s).replace(/\\/g,'\\\\').replace(/\(/g,'\\(').replace(/\)/g,'\\)').replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g,' ')}
  function wrapLines(lines,max){const out=[];(lines||[]).forEach(line=>{line=String(line==null?'':line).replace(/\s+/g,' ').trim(); if(!line){out.push('');return} while(line.length>max){let cut=line.lastIndexOf(' ',max); if(cut<20)cut=max; out.push(line.slice(0,cut)); line=line.slice(cut).trim();} out.push(line)});return out}
  function downloadBlob(content,type,name){const blob=content instanceof Blob?content:new Blob([content],{type}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download=name; document.body.appendChild(a); a.click(); setTimeout(()=>{URL.revokeObjectURL(a.href);a.remove()},500)}
  function makePDF(title,lines,filename){try{let content=wrapLines([title,'OceanJet Baggage System','Generated: '+now(),'Reference: '+uid('PDF'),''].concat(lines||[]).concat(['','Footer: Generated by OceanJet Baggage System']),86); if(content.filter(x=>x.trim()).length<7) content=wrapLines([title,'No saved data was found, but this safety engine prevented a blank PDF.','Open calculator/claim/scanner first, then export again.','Generated: '+now(),'Footer: Generated by OceanJet Baggage System'],86); const enc=new TextEncoder(); const objs=[null]; const kids=[]; objs[1]='<< /Type /Catalog /Pages 2 0 R >>'; objs[2]=''; objs[3]='<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>'; for(let p=0;p<content.length;p+=44){const page=content.slice(p,p+44); let stream=''; page.forEach((line,i)=>{const y=750-i*16; const size=(p===0&&i===0)?15:(i<4?10:9); stream+=`BT /F1 ${size} Tf 1 0 0 1 44 ${y} Tm (${pdfEscape(line)}) Tj ET\n`;}); const sid=objs.length; objs[sid]=`<< /Length ${enc.encode(stream).length} >>\nstream\n${stream}endstream`; const pid=objs.length; objs[pid]=`<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] /Resources << /Font << /F1 3 0 R >> >> /Contents ${sid} 0 R >>`; kids.push(`${pid} 0 R`);} objs[2]=`<< /Type /Pages /Kids [${kids.join(' ')}] /Count ${kids.length} >>`; let pdf='%PDF-1.4\n'; const offs=[0]; for(let i=1;i<objs.length;i++){offs[i]=enc.encode(pdf).length; pdf+=`${i} 0 obj\n${objs[i]}\nendobj\n`;} const xref=enc.encode(pdf).length; pdf+=`xref\n0 ${objs.length}\n0000000000 65535 f \n`; for(let i=1;i<objs.length;i++)pdf+=String(offs[i]).padStart(10,'0')+' 00000 n \n'; pdf+=`trailer << /Size ${objs.length} /Root 1 0 R >>\nstartxref\n${xref}\n%%EOF`; downloadBlob(pdf,'application/pdf',filename||'oceanjet_report.pdf'); audit('pdf export',title); toast('PDF exported with visible real data.'); return true;}catch(e){console.error(e);toast('PDF failed safely; data remains on screen.');return false}}
  function receiptLines(){const out=['OFFICIAL BAGGAGE FEE RECEIPT']; const r=$('receipt'); const t=(r?.innerText||r?.textContent||'').trim(); if(t&&t.length>20&&!/undefined/i.test(t)){out.push(...t.split(/\n+/).map(x=>x.trim()).filter(Boolean));return out} try{if(window.lastReceiptText)out.push(...String(window.lastReceiptText).split(/\n+/).filter(Boolean))}catch(e){} const db=window.DB||read('off_baggage_v14',{}); const h=Array.isArray(db.history)?db.history:Array.isArray(db.comps)?db.comps:[]; const last=h[h.length-1]; if(last){out.push('Latest saved calculator transaction');out.push('Route: '+(last.route||''));out.push('Mode: '+(last.mode||''));out.push('Class: '+(last.cls||''));out.push('Passenger count: '+(last.pax||''));out.push('Baggage weight: '+(last.weight||'')+' kg');out.push('Total: '+peso(last.total));out.push('Time: '+(last.time||''));return out} ['calcRoute','calcMode','calcClass','pax','weight','rounding'].forEach(id=>{const el=$(id); if(el)out.push(id+': '+(el.value||el.textContent||''))}); if(out.length<3)out.push('No active baggage receipt yet. Compute baggage fee first, then export PDF.'); return out}
  function claimLines(id){let c=id?allClaims().map(normClaim).find(x=>x.id===id):allClaims().map(normClaim)[0]; if(!c)return ['PASSENGER CLAIM RECEIPT','No claim saved yet. Submit a damage claim first.']; return ['PASSENGER CLAIM RECEIPT','Claim ID: '+c.id,'Passenger Name / Last Name: '+c.lastName,'PSN: '+c.psn,'Route / Trip: '+c.route,'Baggage Details: '+c.baggage,'Damage Details: '+c.damage,'Severity: '+c.severity,'Claim Status: '+c.status,'Staff / Role: '+c.staff,'Date and Time: '+c.created,'Reference ID: '+c.id,'Timeline: Submitted -> Verified -> Processing -> Resolved','Notes: '+c.notes]}
  function evidenceLines(id){let e=id?read(EVIDENCE_KEY,[]).find(x=>x.id===id):read(EVIDENCE_KEY,[])[0]||lastAnalysis; if(!e)return ['DAMAGE EVIDENCE REPORT','No evidence saved yet. Use Smart AR Damage Scanner to capture/upload a real image first.']; return ['DAMAGE EVIDENCE REPORT','Evidence ID: '+e.id,'Claim / Stub / Tag: '+(e.claimRef||''),'Destination / Route: '+(e.destination||'Not detected from image'),'Auto Color: '+e.color,'Auto Size: '+e.size,'Auto Baggage Type: '+e.baggageType,'Auto Damage: '+e.damageType,'Severity: '+e.severity,'Evidence Quality Score: '+e.quality+'%','Barcode / QR: '+e.barcode,'Image Analysis: '+e.autoSummary,'Photo stored locally: '+(e.photo?'Yes':'No'),'Staff / Shift: '+(e.staff||''),'Date and Time: '+e.createdAt,'Notes: '+e.notes]}
  function dailyLines(){const claims=allClaims().map(normClaim); const open=claims.filter(c=>!/resolved|closed|rejected/i.test(c.status)); return ['STAFF DAILY COUNTER SUMMARY','Date: '+today(),'Claim count: '+claims.length,'Open queue: '+open.length,'Verified: '+claims.filter(c=>/verified/i.test(c.status)).length,'Processing: '+claims.filter(c=>/processing/i.test(c.status)).length,'Resolved: '+claims.filter(c=>/resolved|closed/i.test(c.status)).length,'Rejected: '+claims.filter(c=>/rejected/i.test(c.status)).length,'Severe damage: '+claims.filter(c=>/severe/i.test(c.severity)).length,'Staff / Role: '+roleLabel(),''].concat(claims.slice(0,60).map((c,i)=>`${i+1}. ${c.id} | ${c.lastName} | ${c.route} | ${c.damage} | ${c.status}`))}
  function masterLines(){const claims=allClaims().map(normClaim); return ['ADMIN MASTER CLAIM LOG','Total records: '+claims.length,'Generated by role: '+roleLabel(),''].concat(claims.slice(0,140).map((c,i)=>`${i+1}. ${c.id} | PSN ${c.psn} | ${c.lastName} | ${c.route} | ${c.damage} | ${c.severity} | ${c.status} | ${c.staff}`))}
  function auditLines(){const arr=read(AUDIT_KEY,[]); return ['TRANSACTION AUDIT REPORT','Total audit records: '+arr.length,''].concat(arr.slice(0,150).map((a,i)=>`${i+1}. ${a.at} | ${a.role} | ${a.action} | ${a.detail}`))}
  window.downloadReceipt=function(){return makePDF('OceanJet Official Baggage Receipt',receiptLines(),'oceanjet_baggage_receipt_'+Date.now()+'.pdf')};
  window.oj49PDFClaim=function(id){return makePDF('OceanJet Passenger Claim Receipt',claimLines(id),'oceanjet_claim_receipt_'+(id||Date.now())+'.pdf')};
  window.oj49PDFEvidence=function(id){return makePDF('OceanJet Damage Evidence Report',evidenceLines(id),'oceanjet_damage_evidence_'+(id||Date.now())+'.pdf')};
  window.oj49PDFDaily=function(){return makePDF('OceanJet Staff Daily Summary',dailyLines(),'oceanjet_staff_daily_summary_'+today()+'.pdf')};
  window.oj49PDFMaster=function(){return makePDF('OceanJet Admin Master Log',masterLines(),'oceanjet_admin_master_log_'+today()+'.pdf')};
  window.oj49PDFAudit=function(){return makePDF('OceanJet Transaction Audit Report',auditLines(),'oceanjet_transaction_audit_'+today()+'.pdf')};
  window.oj35ExportReceiptPDF=window.downloadReceipt; window.oj43ExportReceiptPDF=window.downloadReceipt; window.oj35ExportClaimsPDF=window.oj49PDFMaster; window.oj35ExportTransactionsPDF=window.oj49PDFDaily; window.oj35ExportSystemPDF=window.oj49PDFAudit;
  function renderReports(){const v=showOnly('oj49-reports'); v.innerHTML=`<div class="oj49-shell"><div class="oj49-hero"><div class="oj49-title"><div><h2>PDF Export Center</h2><div class="oj49-sub">Local PDF engine: visible text, real calculator/claim/evidence data, no blank pages if libraries/CDNs fail.</div></div>${chip('REAL PDF','ok')}</div></div><div class="oj49-card" style="margin-top:14px"><div class="oj49-tools"><button class="primary" onclick="downloadReceipt()">Passenger Baggage Receipt</button><button onclick="oj49PDFClaim()">Claim Status Receipt</button><button onclick="oj49PDFEvidence()">Damage Evidence Report</button><button onclick="oj49PDFDaily()">Staff Daily Summary</button><button onclick="oj49PDFMaster()">Admin Master Log</button><button onclick="oj49PDFAudit()">Transaction Audit</button></div></div><div class="oj49-card" style="margin-top:14px"><h3>Preview</h3><div class="oj49-preview">${esc(receiptLines().concat(['','','--- CLAIM PREVIEW ---'],claimLines().slice(0,12),['','','--- DAILY SUMMARY PREVIEW ---'],dailyLines().slice(0,12)).join('\n'))}</div></div></div>`;}
  function renderDaily(){if(!can('counter')){renderLogin();return} const v=showOnly('oj49-daily'); v.innerHTML=`<div class="oj49-shell"><div class="oj49-hero"><div class="oj49-title"><div><h2>Daily Counter Summary</h2><div class="oj49-sub">Cashier/staff transaction summary for claims, verification, and receipts.</div></div>${chip(today(),'gold')}</div></div><div class="oj49-card" style="margin-top:14px"><div class="oj49-preview">${esc(dailyLines().join('\n'))}</div><div class="oj49-tools"><button class="primary" onclick="oj49PDFDaily()">Export Daily Summary PDF</button></div></div></div>`;}
  function renderBackup(){if(!can('admin')){renderLogin();return} const v=showOnly('oj49-backup'); v.innerHTML=`<div class="oj49-shell"><div class="oj49-hero"><div class="oj49-title"><div><h2>Backup / Restore</h2><div class="oj49-sub">Admin-only local JSON backup for claims, evidence, audit, and role settings.</div></div>${chip('ADMIN ONLY','red')}</div></div><div class="oj49-card" style="margin-top:14px"><div class="oj49-tools"><button class="primary" onclick="oj49Backup()">Download Backup JSON</button><button class="danger" onclick="document.getElementById('oj49RestoreFile').click()">Restore JSON</button><input id="oj49RestoreFile" type="file" accept="application/json" style="display:none" onchange="oj49Restore(this.files)"></div><div class="oj49-note">Restore merges supported V49 keys only and does not delete the original calculator code.</div></div></div>`;}
  window.oj49Backup=function(){const data={version:VERSION,createdAt:now(),claims:read(CLAIMS_KEY,[]),evidence:read(EVIDENCE_KEY,[]),audit:read(AUDIT_KEY,[]),role:getRole()}; downloadBlob(JSON.stringify(data,null,2),'application/json','oceanjet_v49_backup_'+today()+'.json'); audit('backup export','json')};
  window.oj49Restore=async function(files){try{const f=files&&files[0]; if(!f)return; const txt=await f.text(); const data=JSON.parse(txt); if(Array.isArray(data.claims))write(CLAIMS_KEY,data.claims); if(Array.isArray(data.evidence))write(EVIDENCE_KEY,data.evidence); if(Array.isArray(data.audit))write(AUDIT_KEY,data.audit); audit('backup restore',f.name); toast('Backup restored.'); renderHome();}catch(e){toast('Restore failed: invalid JSON.')}};
  function renderSettings(){const v=showOnly('oj49-settings'); v.innerHTML=`<div class="oj49-shell"><div class="oj49-hero"><div class="oj49-title"><div><h2>System Settings</h2><div class="oj49-sub">Stable full-source build using V43 base plus reviewed V45/V46 PDF and scanner ideas. V48 tiny-shell issue is not used.</div></div>${chip(VERSION,'ok')}</div></div><div class="oj49-grid"><div class="oj49-card"><h3>Role</h3><div class="oj49-tools"><button onclick="oj49SetRole('pax')">Passenger</button><button class="gold" onclick="oj49SetRole('cashier')">Cashier</button><button class="danger" onclick="oj49SetRole('admin')">Admin</button></div></div><div class="oj49-card"><h3>Stability</h3><div class="oj49-note">Camera and scanner do not auto-run. Drawer does not auto-open. PDF does not depend on jsPDF/CDN.</div></div></div></div>`;}
  window.oj49SetRole=setRole;

  function open49(target){const t=String(target||'home').replace(/^view-/,'').toLowerCase(); if(t==='logout'){setRole('pax');return} if(['home','dashboard','passenger'].includes(t))return renderHome(); if(['login','login-cashier','login-admin','role-login','staff-login'].includes(t))return renderLogin(); if(['start-claim','claim','lostbaggage','damageclaim'].includes(t))return renderStartClaim(); if(['track','claimstatus','status'].includes(t))return renderTrack(); if(['scanner','ar','damage','damagedetector','damage-scanner','v11-damage','oj46-scanner'].includes(t))return renderScanner(); if(['staff','staffcounter','counter','pending','verify'].includes(t))return renderStaffCounter(); if(['admin','control','controltower'].includes(t))return renderAdmin(); if(['master','master-log'].includes(t))return renderMaster(); if(['audit','transaction-audit'].includes(t))return renderAudit(); if(['reports','pdf','pdf-center','oj43-reports','oj46-pdf-center','dailyreport'].includes(t))return renderReports(); if(['daily','summary'].includes(t))return renderDaily(); if(['backup','restore'].includes(t))return renderBackup(); if(['settings','advanced'].includes(t))return renderSettings(); if(['calculator','fares','schedules','history'].includes(t)){try{closeDrawer49(); if(t==='calculator'&&typeof window.buildCalculator==='function'){window.buildCalculator();showOnly('calculator');return} if(oldNavigate)return oldNavigate(t); if(oldShowView)return oldShowView(t);}catch(e){console.warn('legacy open failed',e)} } return renderHome();}
  window.oj49Open=open49;
  function patchLegacy(){oldNavigate=window.navigate||oldNavigate; oldShowView=window.showView||oldShowView; oldOj42Open=window.oj42Open||oldOj42Open; oldOj43Open=window.oj43Open||oldOj43Open; oldBuildDrawer=window.buildDrawerMenu||oldBuildDrawer; window.navigate=open49; window.showView=open49; window.oj42Open=open49; window.oj43Open=open49; window.toggleDrawer=toggleDrawer49; window.closeDrawer=closeDrawer49; window.buildDrawerMenu=renderDrawer;}
  function patchReceiptButton(){try{const r=$('receipt'); if(r&&!r.querySelector('.oj49-pdf-btn')){const b=document.createElement('button');b.type='button';b.className='oj49-pdf-btn oj49-btn primary';b.style.cssText='margin:12px auto 0;display:block;max-width:220px';b.textContent='Download Real PDF';b.onclick=window.downloadReceipt;r.appendChild(b)}}catch(e){}}
  function boot(){try{patchLegacy();renderDrawer();document.body.classList.add('oj49-ready');const rb=$('roleBadge'); if(rb)rb.textContent=roleLabel(); closeDrawer49(); setTimeout(closeDrawer49,250); patchReceiptButton(); const r=$('receipt'); if(r){new MutationObserver(patchReceiptButton).observe(r,{childList:true,subtree:false});} const current=document.querySelector('.view.active'); if(!current||/dashboard/.test(current.id))renderHome(); audit('boot',VERSION); console.log(VERSION+' loaded; full index preserved; V48 tiny shell not used.');}catch(e){console.error('V49 boot recovered',e); try{renderHome()}catch(_){}}}
  if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',()=>setTimeout(boot,120),{once:true}); else setTimeout(boot,120);
})();
